section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/diary-study-basics.json",
  "title": "Diary Study Basics",
  "type": "object",
  "required": [
    "artefact_id",
    "participants",
    "entry_templates",
    "reminder_schedule",
    "compliance_threshold",
    "exit_interview_hook",
    "evidence",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date",
      "minLength": 1
    },
    "participants": {
      "type": "array",
      "description": "{id, recruit_source, consent}",
      "minItems": 1
    },
    "entry_templates": {
      "type": "object",
      "description": "daily + event-triggered fields"
    },
    "reminder_schedule": {
      "type": "array",
      "description": "cadence + channel",
      "minItems": 1
    },
    "compliance_threshold": {
      "type": "object",
      "description": "drop-off + remediation rules"
    },
    "exit_interview_hook": {
      "type": "string",
      "description": "anchor question for the final debrief",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation}",
      "minItems": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}

example.code:
{
  "owner": "ruslan@faion.net",
  "last_touched": "2026-05-23T12:00:00Z",
  "template_version": "1.1.0",
  "artefact_id": "diary-study-basics-2026-05-23",
  "participants": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "entry_templates": {
    "key": "value"
  },
  "reminder_schedule": [
    {
      "source": "https://example.com/source-1",
      "citation": "verbatim quote from source"
    }
  ],
  "compliance_threshold": {
    "key": "value"
  },
  "exit_interview_hook": "draft",
  "evidence": [
    {
      "source": "https://example.com/transcript/1",
      "citation": "verbatim user quote"
    }
  ]
}
